// Tests for <stdexcept>, ported from libc++ test suite.
// Covers: logic_error, invalid_argument, domain_error, length_error,
//         out_of_range, runtime_error, range_error, overflow_error,
//         underflow_error — inheritance, what() content, copy semantics.
// No main(); auto-generated by tools/gen_main.sh.
#include <stdexcept>
#include "test.h"

// Helper: compare two C-strings
static bool streq(const char* a, const char* b) {
    return __builtin_strcmp(a, b) == 0;
}

//===----------------------------------------------------------------------===//
// test_stdexcept_logic_error
//===----------------------------------------------------------------------===//
void test_stdexcept_logic_error() {
    // Inheritance
    static_assert(__is_base_of(std::exception,   std::logic_error));
    static_assert(__is_polymorphic(std::logic_error));

    const char* msg = "logic_error message";

    // Construct from const char*
    std::logic_error e(msg);
    CHECK(streq(e.what(), msg));

    // Copy constructor
    std::logic_error e2(e);
    CHECK(streq(e2.what(), msg));

    // Copy assignment
    std::logic_error e3("other");
    e3 = e;
    CHECK(streq(e3.what(), msg));

    // Access through base pointer
    std::exception* p = &e;
    CHECK(streq(p->what(), msg));
}

//===----------------------------------------------------------------------===//
// test_stdexcept_invalid_argument
//===----------------------------------------------------------------------===//
void test_stdexcept_invalid_argument() {
    static_assert(__is_base_of(std::exception,   std::invalid_argument));
    static_assert(__is_base_of(std::logic_error, std::invalid_argument));
    static_assert(__is_polymorphic(std::invalid_argument));

    const char* msg = "invalid_argument message";
    std::invalid_argument e(msg);
    CHECK(streq(e.what(), msg));

    std::invalid_argument e2(e);
    CHECK(streq(e2.what(), msg));

    std::invalid_argument e3("placeholder");
    e3 = e;
    CHECK(streq(e3.what(), msg));
}

