//===----------------------------------------------------------------------===//
// test_stdexcept_refcount
// Verify that the refcount storage is shared and that the string survives
// across multiple copies and outlives the original.
//===----------------------------------------------------------------------===//
void test_stdexcept_refcount() {
    const char* msg = "refcount test message";

    // Create a copy that outlives the original to exercise the refcount path.
    std::logic_error* p = nullptr;
    {
        std::logic_error orig(msg);
        p = new std::logic_error(orig); // copy; orig destroyed at end of block
    }
    // The copy must still have the message intact
    CHECK(streq(p->what(), msg));
    delete p;
}
